<template>
    <div class="note-wrapper">
        <particles-bg class="particles-bg" type="cobweb" :bg="true" />
        <div class="note-left">
            <div class="navbar-title">前端学习笔记</div>
            <div class="navbar-list" @click="selectArticle(item)" v-for="(item, index) in articleList" :key="index" :class="{ active: store.state.curWritingArticleId == item.id }">
                {{ item.title }}
            </div>
        </div>
        <div class="note-right">
            <div class="note-body" v-if="curArticle">
                <div class="note-title">
                    <div class="title">{{ curArticle.title }}</div>
                    <div class="info">
                        <UserOutlined style="margin-right:5px" />
                        <div>{{ curArticle.author }}</div>
                        <ClockCircleOutlined style="margin-right:5px;margin-left:16px" />
                        <div>{{ curArticle.createTime }}</div>
                        <TagOutlined style="margin-right:5px;margin-left:16px" />
                        <div v-if="curArticle.tags">{{ curArticle.tags }}</div>
                    </div>
                    <div class="note-editor" @click="editNote()" v-if="isAdmin">
                        <EditOutlined />
                        <div style="margin-left:12px">编辑</div>
                    </div>
                </div>
                <v-md-editor class="editor" v-model="curArticle.content" mode="preview" @copy-code-success="handleCopyCodeSuccess"></v-md-editor>
            </div>
        </div>
    </div>
</template>
<script>
import { reactive, inject, onMounted, onBeforeUnmount, ref } from "vue";
import { useStore } from "vuex";
import { useRouter } from "vue-router";
import { UserOutlined, ClockCircleOutlined, TagOutlined, EditOutlined } from "@ant-design/icons-vue";
import { message } from "ant-design-vue";
import { ParticlesBg } from "particles-bg-vue";
export default {
    components: {
        UserOutlined,
        ClockCircleOutlined,
        TagOutlined,
        EditOutlined,
        ParticlesBg
    },
    setup() {
        const $api = inject("$api");
        const store = useStore();
        const router = useRouter();

        let articleList = ref([]);
        let isEdit = ref(false);
        const params = reactive({
            pageSize: 0,
            pageNumber: 1
        });
        let curArticle = ref(null);
        const isAdmin = ref(false);

        // 获取文章列表
        const getArticleList = () => {
            articleList.value = [];
            $api.article.getArticleList(params).then(res => {
                articleList.value = res.data.datas;
                if (!store.state.curWritingArticleId) {
                    store.commit("setCurWritingArticleId", articleList.value[0].id);
                }
                getArticle();
            });
        };

        // 根据id获取文章
        const getArticle = () => {
            $api.article.getArticle({ id: store.state.curWritingArticleId }).then(res => {
                curArticle.value = res.data;
            });
        };

        // 代码复制
        const handleCopyCodeSuccess = () => {
            message.success("代码已复制");
        };

        // 选择文章
        const selectArticle = data => {
            store.commit("setCurWritingArticleId", data.id);
            getArticle();
        };

        //编辑文章
        const editNote = () => {
            store.commit("setCurWritingArticleId", store.state.curWritingArticleId);
            isEdit.value = true;
            router.push({ path: "/editor" });
        };

        onMounted(() => {
            getArticleList();
            isAdmin.value = JSON.parse(localStorage.getItem("isAdmin"));
        });

        onBeforeUnmount(() => {
            if (!isEdit.value) {
                store.commit("setCurWritingArticleId", null);
            }
            isEdit.value = false;
        });

        return {
            params,
            articleList,
            store,
            curArticle,
            handleCopyCodeSuccess,
            selectArticle,
            editNote,
            isEdit,
            isAdmin
        };
    }
};
</script>

